solution:
def count_components(n, edges):
    graph = {i: [] for i in range(n)}
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)
    visited = set()
    def go(node):
        visited.add(node)
        for nb in graph[node]:
            if nb not in visited:
                go(nb)
    count = 0
    for i in range(n):
        if i not in visited:
            count += 1
            go(i)
    return count

